file.content:
{
	"$schema": "https://schemas.wp.org/trunk/block.json",
	"apiVersion": 3,
	"name": "gatherpress/relations-roadmap",
	"version": "0.1.0",
	"title": "GatherPress Relations Roadmap",
	"category": "widgets",
	"icon": "networking",
	"description": "A comprehensive architectural roadmap for connecting persons to productions (or any special post type) with roles in WordPress — powered by GatherPress shadow taxonomies, covering data modeling, block design, and scaling strategies.",
	"example": {
		"attributes": {
			"showDataModeling": true,
			"showCastCrew": true,
			"showEnsemble": true,
			"showVisualizations": true,
			"showScaling": true,
			"showImplementation": true
		}
	},
	"attributes": {
		"showDataModeling": {
			"type": "boolean",
			"default": true
		},
		"showCastCrew": {
			"type": "boolean",
			"default": true
		},
		"showEnsemble": {
			"type": "boolean",
			"default": true
		},
		"showVisualizations": {
			"type": "boolean",
			"default": true
		},
		"showScaling": {
			"type": "boolean",
			"default": true
		},
		"showImplementation": {
			"type": "boolean",
			"default": true
		}
	},
	"supports": {
		"html": false,
		"align": [ "wide", "full" ],
		"spacing": {
			"margin": true,
			"padding": true
		},
		"color": {
			"background": true,
			"text": true
		},
		"typography": {
			"fontSize": true
		}
	},
	"textdomain": "gatherpress-relations",
	"editorScript": "file:./index.js",
	"editorStyle": "file:./index.css",
	"style": "file:./style-index.css",
	"viewScript": "file:./view.js",
	"render": "file:./render.php"
}

/** * Block registration for GatherPress Relations Roadmap. * * HOW this works: * ─────────────── * `registerBlockType` reads the block name from `metadata.name` * (which comes from block.json: "gatherpress/relations-roadmap") * and associates the `edit` component for the editor UI. * * WHY no `save` export? * This is a dynamic block — the frontend markup is produced entirely * by `render.php` on each page load. Returning `null` from `save` * tells WordPress to store only the block comment delimiter and * serialised attributes in `post_content`, e.g.: * * ```html * <!-- wp:gatherpress/relations-roadmap {"showDataModeling":true} /--> * ``` * * @see https://developer.wordpress.org/block-editor/reference-guides/block-api/block-registration/ * * @package GatherPressRelations */ import { registerBlockType } from '@wordpress/blocks';
/** * Shared styles applied in both editor and frontend contexts. * * WHY imported here? * Webpack bundles any SCSS imported from the entry point into * `style-index.css`, which block.json references as the `style` asset. * This ensures the same visual baseline in both environments. */ import './style.scss';
/** * Internal dependencies — the editor-only component. */ import Edit from './edit'; import metadata from './block.json';
/** * Register the block type. * * PAYLOAD registered: * ``` * { * name: "gatherpress/relations-roadmap", * edit: Edit, // React component for the editor * save: () => null // Dynamic block — no saved markup * } * ``` */ registerBlockType( metadata.name, { /** * Editor component — renders a compact placeholder. * * @see ./edit.js */ edit: Edit, } );

/**
 * Edit component for the GatherPress Relations Roadmap block.
 *
 * HOW this component works:
 * ─────────────────────────
 * In the editor canvas it renders a compact placeholder card that
 * shows the roadmap title, a brief description, and a list of the
 * sections that are currently enabled. This keeps the editor
 * lightweight — the full roadmap (with collapsible sections, code
 * samples, diagrams) is rendered only on the frontend via render.php.
 *
 * WHY a placeholder instead of the full roadmap?
 * 1. The roadmap is long (~3 000 words). Rendering it inside the
 *    editor would make the post canvas unwieldy and slow to scroll.
 * 2. The frontend version uses vanilla JS interactivity (collapsible
 *    panels, sticky TOC) that has no editor equivalent.
 * 3. A compact card communicates "this block exists and is configured"
 *    without overwhelming the editing experience.
 *
 * The sidebar (InspectorControls) exposes six ToggleControls — one
 * per roadmap section — so the author can choose which sections
 * appear on the frontend.
 *
 * @package GatherPressRelations
 */

import { __ } from '@wordpress/i18n';
import { useBlockProps, InspectorControls } from '@wordpress/block-editor';
import {
	PanelBody,
	ToggleControl,
	Icon,
} from '@wordpress/components';

import './editor.scss';

/**
 * Section metadata used to render both the sidebar toggles and the
 * placeholder summary list.
 *
 * Each entry maps a block attribute key to a human-readable label
 * and a Dashicon slug so the placeholder card can show a visual
 * checklist of enabled sections.
 *
 * @type {Array<{key: string, label: string, icon: string}>}
 *
 * Example entry:
 * ```
 * { key: 'showDataModeling', label: 'Data Modeling & Architecture', icon: 'database' }
 * ```
 */
const SECTIONS = [
	{
		key: 'showDataModeling',
		label: __( 'Data Modeling & Architecture', 'gatherpress-relations' ),
		icon: 'database',
	},
	{
		key: 'showCastCrew',
		label: __( 'Cast & Crew List Block', 'gatherpress-relations' ),
		icon: 'groups',
	},
	{
		key: 'showEnsemble',
		label: __( 'People / Ensemble Blocks', 'gatherpress-relations' ),
		icon: 'id-alt',
	},
	{
		key: 'showVisualizations',
		label: __( 'Smart Data-Relation Visualizations', 'gatherpress-relations' ),
		icon: 'chart-area',
	},
	{
		key: 'showScaling',
		label: __( 'Scaling & Performance', 'gatherpress-relations' ),
		icon: 'performance',
	},
	{
		key: 'showImplementation',
		label: __( 'Implementation Roadmap', 'gatherpress-relations' ),
		icon: 'flag',
	},
];

/**
 * Editor UI for the GatherPress Relations Roadmap block.
 *
 * @param {Object}   props               - Block props provided by the editor.
 * @param {Object}   props.attributes    - Current attribute values.
 * @param {boolean}  props.attributes.showDataModeling    - Whether the Data Modeling section is visible.
 * @param {boolean}  props.attributes.showCastCrew        - Whether the Cast & Crew section is visible.
 * @param {boolean}  props.attributes.showEnsemble        - Whether the Ensemble section is visible.
 * @param {boolean}  props.attributes.showVisualizations  - Whether the Visualizations section is visible.
 * @param {boolean}  props.attributes.showScaling         - Whether the Scaling section is visible.
 * @param {boolean}  props.attributes.showImplementation  - Whether the Implementation section is visible.
 * @param {Function} props.setAttributes - Setter for block attributes.
 * @returns {Element} The editor placeholder element.
 */
export default function Edit( { attributes, setAttributes } ) {
	/**
	 * `useBlockProps()` returns the HTML attributes (className, id, etc.)
	 * that the block wrapper needs so that the editor can:
	 * - apply the block's selection outline,
	 * - handle drag/drop and focus,
	 * - inject generated class names matching the `wp-block-*` pattern.
	 */
	const blockProps = useBlockProps();

	/**
	 * Count how many sections are currently enabled.
	 * Used in the placeholder to give the author a quick status line
	 * like "5 of 6 sections enabled".
	 *
	 * @type {number}
	 */
	const enabledCount = SECTIONS.filter(
		( section ) => attributes[ section.key ]
	).length;

	return (
		<>
			{ /*
			  * InspectorControls — rendered in the sidebar panel.
			  *
			  * WHY here?
			  * Placing toggles in the sidebar keeps the canvas clean
			  * while giving authors full control over which sections
			  * render on the frontend.
			  */ }
			<InspectorControls>
				<PanelBody
					title={ __(
						'Roadmap Sections',
						'gatherpress-relations'
					) }
					initialOpen={ true }
				>
					{ SECTIONS.map( ( section ) => (
						<ToggleControl
							__nextHasNoMarginBottom
							key={ section.key }
							label={ section.label }
							checked={ !! attributes[ section.key ] }
							onChange={ ( value ) =>
								setAttributes( {
									[ section.key ]: value,
								} )
							}
						/>
					) ) }
				</PanelBody>
			</InspectorControls>

			{ /*
			  * Editor placeholder — a compact card.
			  *
			  * HOW it communicates:
			  * - Title with a networking icon confirms the block type.
			  * - Description explains what renders on the frontend.
			  * - Section checklist shows which sections are on/off.
			  * - A status bar summarises "X of 6 sections enabled".
			  */ }
			<div { ...blockProps }>
				<div className="gatherpress-relations__editor-placeholder">
					<div className="gatherpress-relations__editor-placeholder-header">
						<Icon icon="networking" size={ 28 } />
						<h3 className="gatherpress-relations__editor-placeholder-title">
							{ __(
								'Shadow Taxonomy Relations Roadmap',
								'gatherpress-relations'
							) }
						</h3>
					</div>

					<p className="gatherpress-relations__editor-placeholder-description">
						{ __(
							'This block renders a comprehensive architectural roadmap on the frontend — covering shadow taxonomy data modeling, block design patterns, and scaling strategies for connecting persons to productions (or any special post type) with roles, powered by GatherPress shadow taxonomies.',
							'gatherpress-relations'
						) }
					</p>

					<ul className="gatherpress-relations__editor-placeholder-sections">
						{ SECTIONS.map( ( section ) => (
							<li
								key={ section.key }
								className={ `gatherpress-relations__editor-placeholder-section ${
									attributes[ section.key ]
										? 'gatherpress-relations__editor-placeholder-section--enabled'
										: 'gatherpress-relations__editor-placeholder-section--disabled'
								}` }
							>
								<Icon
									icon={ section.icon }
									size={ 16 }
								/>
								<span>{ section.label }</span>
							</li>
						) ) }
					</ul>

					<div className="gatherpress-relations__editor-placeholder-status">
						{ enabledCount } / { SECTIONS.length }{ ' ' }
						{ __(
							'sections enabled',
							'gatherpress-relations'
						) }
					</div>
				</div>
			</div>
		</>
	);
}

/**
 * Shared styles for the GatherPress Relations Roadmap block.
 *
 * NAMING CONVENTION: BEM (Block Element Modifier)
 * ────────────────────────────────────────────────
 * Block:    .gatherpress-relations
 * Element:  .gatherpress-relations__toc
 * Modifier: .gatherpress-relations__section--collapsed
 *
 * WHY BEM?
 * BEM produces flat, predictable selectors that avoid specificity wars,
 * are easy to grep, and map cleanly to component boundaries.
 *
 * WHY nested?
 * SCSS nesting mirrors the DOM tree, making it easy to see which
 * styles belong to which sub-component. Each nesting level corresponds
 * to a BEM element or modifier.
 *
 * HOW colours work:
 * We use CSS custom properties with fallback values so the block
 * inherits theme tokens when available but remains legible in any theme.
 *
 * @package GatherPressRelations
 */

/* ──────────────────────────────────────────────
 * CSS Custom Properties — design tokens
 * ────────────────────────────────────────────── */
:root {
	/**
	 * WHY custom properties?
	 * They let us define the palette once and reference it everywhere.
	 * A theme can override these via its own :root declaration or
	 * through theme.json custom values.
	 */
	--gpr-color-bg: #f9fafb;
	--gpr-color-surface: #ffffff;
	--gpr-color-border: #e2e8f0;
	--gpr-color-text: #1e293b;
	--gpr-color-text-muted: #64748b;
	--gpr-color-primary: #3b82f6;
	--gpr-color-primary-hover: #2563eb;
	--gpr-color-primary-light: #eff6ff;
	--gpr-color-accent: #8b5cf6;
	--gpr-color-accent-light: #f5f3ff;
	--gpr-color-success: #10b981;
	--gpr-color-success-light: #ecfdf5;
	--gpr-color-warning: #f59e0b;
	--gpr-color-warning-light: #fffbeb;
	--gpr-color-code-bg: #1e293b;
	--gpr-color-code-text: #e2e8f0;
	--gpr-radius-sm: 6px;
	--gpr-radius-md: 10px;
	--gpr-radius-lg: 16px;
	--gpr-shadow-sm: 0 1px 3px rgb(0 0 0 / 0.08);
	--gpr-shadow-md: 0 4px 12px rgb(0 0 0 / 0.1);
	--gpr-font-mono: "SF Mono", "Fira Code", "Cascadia Code", "Consolas", monospace;
}

/* ──────────────────────────────────────────────
 * Block root
 * ────────────────────────────────────────────── */
.wp-block-gatherpress-relations-roadmap {
	/**
	 * WHY max-width on the block root?
	 * When the block is used without "wide" or "full" alignment, this
	 * caps the content width for comfortable reading (~80ch).
	 * The wide/full alignment classes override this via WordPress's
	 * built-in alignment styles.
	 */
	max-width: 100%;
	font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen-Sans, Ubuntu, Cantarell, "Helvetica Neue", sans-serif;
	line-height: 1.65;
	color: var(--gpr-color-text);
}

/* ──────────────────────────────────────────────
 * Roadmap wrapper — holds TOC + sections
 * ────────────────────────────────────────────── */
.gatherpress-relations {
	/**
	 * WHY a two-column grid?
	 * The left column holds the sticky table of contents (TOC).
	 * The right column holds the scrollable roadmap sections.
	 * On mobile (<768px) this collapses to a single column.
	 */
	display: grid;
	grid-template-columns: 260px 1fr;
	gap: 2rem;
	position: relative;

	/**
	 * Responsive: single column on narrow viewports.
	 */
	@media (max-width: 899px) {
		grid-template-columns: 1fr;
	}

	/* ── Table of Contents ────────────────────── */

	/**
	 * The TOC sidebar. Sticks to the top of the viewport so the user
	 * can navigate sections without scrolling back up.
	 *
	 * WHY sticky?
	 * Long roadmap content can span many viewport-heights. A sticky
	 * TOC keeps navigation always within reach.
	 *
	 * HOW the active state works:
	 * view.js uses IntersectionObserver to detect which section is
	 * in view, then toggles .gatherpress-relations__toc-link--active
	 * on the corresponding TOC link.
	 */
	&__toc {
		position: sticky;
		top: calc(var(--wp-admin--admin-bar--height, 0px) + 2rem);
		align-self: start;
		background: var(--gpr-color-surface);
		border: 1px solid var(--gpr-color-border);
		border-radius: var(--gpr-radius-lg);
		padding: 1.5rem;
		box-shadow: var(--gpr-shadow-sm);
		max-height: calc(100vh - var(--wp-admin--admin-bar--height, 0px) - 4rem);
		overflow-y: auto;

		@media (max-width: 899px) {
			/**
			 * On mobile the TOC is not sticky — it flows inline
			 * above the content so it doesn't consume permanent
			 * screen real-estate.
			 */
			position: static;
			max-height: none;
		}
	}

	&__toc-title {
		font-size: 0.75rem;
		font-weight: 700;
		text-transform: uppercase;
		letter-spacing: 0.08em;
		color: var(--gpr-color-text-muted);
		margin: 0 0 1rem;
		padding-bottom: 0.75rem;
		border-bottom: 1px solid var(--gpr-color-border);
	}

	&__toc-list {
		list-style: none;
		margin: 0;
		padding: 0;
	}

	&__toc-item {
		margin: 0;
		padding: 0;
	}

	/**
	 * TOC link — each link targets a section by ID.
	 *
	 * WHY a left border instead of background?
	 * A left-border indicator is a common pattern in documentation
	 * UIs (VS Code, GitHub). It draws the eye without occluding
	 * the label text.
	 */
	&__toc-link {
		display: block;
		padding: 0.5rem 0.75rem;
		font-size: 0.85rem;
		color: var(--gpr-color-text-muted);
		text-decoration: none;
		border-left: 3px solid transparent;
		border-radius: 0 var(--gpr-radius-sm) var(--gpr-radius-sm) 0;
		transition: all 0.2s ease;

		&:hover {
			color: var(--gpr-color-primary);
			background: var(--gpr-color-primary-light);
			border-left-color: var(--gpr-color-primary);
		}

		/**
		 * Active state — applied by view.js when the section
		 * enters the viewport via IntersectionObserver.
		 */
		&--active {
			color: var(--gpr-color-primary);
			background: var(--gpr-color-primary-light);
			border-left-color: var(--gpr-color-primary);
			font-weight: 600;
		}
	}

	/* ── Sections container ───────────────────── */
	&__content {
		min-width: 0; /* Prevent grid blowout from <pre> elements. */
	}

	/* ── Roadmap header ───────────────────────── */
	&__header {
		margin-bottom: 2rem;
		padding: 2rem;
		background: linear-gradient(135deg, var(--gpr-color-primary-light) 0%, var(--gpr-color-accent-light) 100%);
		border-radius: var(--gpr-radius-lg);
		border: 1px solid var(--gpr-color-border);
	}

	&__main-title {
		font-size: 1.75rem;
		font-weight: 800;
		margin: 0 0 0.5rem;
		color: var(--gpr-color-text);
		line-height: 1.2;
	}

	&__subtitle {
		font-size: 1rem;
		color: var(--gpr-color-text-muted);
		margin: 0;
		line-height: 1.5;
	}

	/* ── Individual section ───────────────────── */

	/**
	 * Each roadmap section is a collapsible panel.
	 *
	 * HOW collapsing works:
	 * view.js toggles the --collapsed modifier on the section element.
	 * The body (__section-body) uses max-height + overflow: hidden
	 * for a smooth CSS transition.
	 */
	&__section {
		background: var(--gpr-color-surface);
		border: 1px solid var(--gpr-color-border);
		border-radius: var(--gpr-radius-lg);
		margin-bottom: 1.25rem;
		box-shadow: var(--gpr-shadow-sm);
		overflow: hidden;
		transition: box-shadow 0.2s ease;

		&:hover {
			box-shadow: var(--gpr-shadow-md);
		}

		/**
		 * Collapsed modifier — hides the section body.
		 *
		 * WHY max-height instead of display:none?
		 * max-height can be transitioned, giving a smooth
		 * expand/collapse animation. display:none cannot.
		 */
		&--collapsed {
			.gatherpress-relations__section-body {
				max-height: 0;
				padding-top: 0;
				padding-bottom: 0;
				opacity: 0;
			}

			.gatherpress-relations__section-chevron {
				transform: rotate(-90deg);
			}
		}
	}

	/**
	 * Section header — clickable toggle for collapse/expand.
	 *
	 * WHY a <button>?
	 * render.php outputs a <button> element so keyboard users can
	 * toggle sections with Enter/Space. This div styles the inner
	 * layout of that button.
	 */
	&__section-header {
		display: flex;
		align-items: center;
		gap: 0.75rem;
		padding: 1.25rem 1.5rem;
		cursor: pointer;
		background: none;
		border: none;
		width: 100%;
		text-align: left;
		font: inherit;
		color: inherit;
		appearance: none;
		transition: background 0.15s ease;

		&:hover {
			background: var(--gpr-color-bg);
		}

		&:focus-visible {
			outline: 2px solid var(--gpr-color-primary);
			outline-offset: -2px;
		}
	}

	/**
	 * Section number badge — a small circle with the section index.
	 */
	&__section-number {
		display: flex;
		align-items: center;
		justify-content: center;
		width: 32px;
		height: 32px;
		border-radius: 50%;
		background: var(--gpr-color-primary);
		color: #fff;
		font-size: 0.8rem;
		font-weight: 700;
		flex-shrink: 0;
	}

	&__section-title {
		flex: 1;
		font-size: 1.1rem;
		font-weight: 700;
		margin: 0;
		color: var(--gpr-color-text);
	}

	&__section-chevron {
		font-size: 1.2rem;
		color: var(--gpr-color-text-muted);
		transition: transform 0.25s ease;
		flex-shrink: 0;
		line-height: 1;
	}

	/**
	 * Section body — the collapsible content area.
	 *
	 * HOW the transition works:
	 * max-height transitions from a large value (5000px, enough for
	 * any section) to 0 when --collapsed is applied. The actual
	 * content height is always less than 5000px, so the transition
	 * duration scales naturally.
	 */
	&__section-body {
		padding: 0 1.5rem 1.5rem;
		max-height: 5000px;
		opacity: 1;
		overflow: hidden;
		transition: max-height 0.4s ease, opacity 0.3s ease, padding 0.3s ease;
	}

	/* ── Content typography ───────────────────── */

	&__heading {
		font-size: 1rem;
		font-weight: 700;
		margin: 1.5rem 0 0.75rem;
		color: var(--gpr-color-text);

		&:first-child {
			margin-top: 0;
		}
	}

	&__paragraph {
		margin: 0 0 1rem;
		color: var(--gpr-color-text);
		line-height: 1.7;
	}

	&__strong {
		font-weight: 700;
		color: var(--gpr-color-text);
	}

	&__em {
		font-style: italic;
	}

	/* ── Code blocks ──────────────────────────── */

	/**
	 * Code block wrapper — dark background for contrast.
	 *
	 * WHY a dark theme?
	 * Code blocks use a dark background to visually separate
	 * them from prose, matching the convention in documentation
	 * sites (MDN, WordPress Developer Resources, etc.).
	 */
	&__code-block {
		background: var(--gpr-color-code-bg);
		border-radius: var(--gpr-radius-md);
		padding: 1.25rem 1.5rem;
		margin: 1rem 0;
		overflow-x: auto;
		border: 1px solid rgba(255, 255, 255, 0.08);
	}

	&__code {
		font-family: var(--gpr-font-mono);
		font-size: 0.82rem;
		color: var(--gpr-color-code-text);
		line-height: 1.6;
		white-space: pre;
		display: block;
	}

	/**
	 * Inline code — used for short references like function names,
	 * hook names, or attribute keys within prose.
	 */
	&__inline-code {
		font-family: var(--gpr-font-mono);
		font-size: 0.85em;
		background: var(--gpr-color-bg);
		padding: 0.15em 0.4em;
		border-radius: 4px;
		border: 1px solid var(--gpr-color-border);
		color: var(--gpr-color-accent);
	}

	/* ── Info / tip / warning cards ───────────── */

	/**
	 * Callout card — used for tips, warnings, and important notes.
	 *
	 * Modifiers set the left-border colour and background:
	 * --tip:     green (success)
	 * --warning: amber (warning)
	 * --info:    blue  (primary)
	 * --key:     purple (accent)
	 */
	&__callout {
		padding: 1rem 1.25rem;
		border-radius: var(--gpr-radius-md);
		margin: 1rem 0;
		border-left: 4px solid var(--gpr-color-primary);
		background: var(--gpr-color-primary-light);

		&--tip {
			border-left-color: var(--gpr-color-success);
			background: var(--gpr-color-success-light);
		}

		&--warning {
			border-left-color: var(--gpr-color-warning);
			background: var(--gpr-color-warning-light);
		}

		&--info {
			border-left-color: var(--gpr-color-primary);
			background: var(--gpr-color-primary-light);
		}

		&--key {
			border-left-color: var(--gpr-color-accent);
			background: var(--gpr-color-accent-light);
		}
	}

	&__callout-title {
		font-weight: 700;
		font-size: 0.85rem;
		text-transform: uppercase;
		letter-spacing: 0.04em;
		margin: 0 0 0.35rem;
	}

	&__callout-text {
		margin: 0;
		font-size: 0.92rem;
		line-height: 1.6;
	}

	/* ── Diagram / visual cards ───────────────── */

	/**
	 * Diagram container — holds ASCII art or visual relationship
	 * representations.
	 *
	 * WHY monospace?
	 * ASCII diagrams require fixed-width characters to maintain
	 * alignment. The dark background and code font distinguish
	 * diagrams from prose.
	 */
	&__diagram {
		background: var(--gpr-color-code-bg);
		border-radius: var(--gpr-radius-md);
		padding: 1.5rem;
		margin: 1rem 0;
		overflow-x: auto;
		border: 1px solid rgba(255, 255, 255, 0.08);
	}

	&__diagram-content {
		font-family: var(--gpr-font-mono);
		font-size: 0.8rem;
		color: var(--gpr-color-code-text);
		line-height: 1.5;
		white-space: pre;
		display: block;
	}

	&__diagram-caption {
		display: block;
		margin-top: 0.75rem;
		font-size: 0.78rem;
		color: var(--gpr-color-text-muted);
		text-align: center;
		font-style: italic;
		font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
	}

	/* ── Comparison table ─────────────────────── */

	/**
	 * Table for comparing approaches (CPT vs Taxonomy vs Users).
	 */
	&__table-wrap {
		overflow-x: auto;
		margin: 1rem 0;
		border-radius: var(--gpr-radius-md);
		border: 1px solid var(--gpr-color-border);
	}

	&__table {
		width: 100%;
		border-collapse: collapse;
		font-size: 0.88rem;

		th,
		td {
			padding: 0.7rem 1rem;
			text-align: left;
			border-bottom: 1px solid var(--gpr-color-border);
		}

		th {
			background: var(--gpr-color-bg);
			font-weight: 700;
			font-size: 0.8rem;
			text-transform: uppercase;
			letter-spacing: 0.04em;
			color: var(--gpr-color-text-muted);
		}

		tr:last-child td {
			border-bottom: none;
		}

		tr:hover td {
			background: var(--gpr-color-primary-light);
		}
	}

	/* ── Unordered & ordered lists ────────────── */
	&__list {
		margin: 0.75rem 0;
		padding-left: 1.5rem;

		li {
			margin-bottom: 0.4rem;
			line-height: 1.6;
		}
	}

	/* ── Phase / milestone cards ──────────────── */

	/**
	 * Phase card — used in the Implementation Roadmap section
	 * to show milestones with colour-coded priority indicators.
	 */
	&__phase {
		background: var(--gpr-color-bg);
		border: 1px solid var(--gpr-color-border);
		border-radius: var(--gpr-radius-md);
		padding: 1.25rem;
		margin: 0.75rem 0;

		&--alpha {
			border-left: 4px solid var(--gpr-color-success);
		}

		&--beta {
			border-left: 4px solid var(--gpr-color-primary);
		}

		&--ga {
			border-left: 4px solid var(--gpr-color-accent);
		}

		&--future {
			border-left: 4px solid var(--gpr-color-warning);
		}
	}

	&__phase-title {
		font-weight: 700;
		font-size: 0.95rem;
		margin: 0 0 0.5rem;
	}

	&__phase-text {
		margin: 0;
		font-size: 0.9rem;
		color: var(--gpr-color-text-muted);
		line-height: 1.6;
	}
}

/**
 * Editor-only styles for the GatherPress Relations Roadmap block.
 *
 * HOW these are scoped:
 * ─────────────────────
 * block.json declares `editorStyle: "file:./index.css"` which maps
 * to the compiled output of this file. WordPress enqueues it only
 * in the editor context, so none of these rules reach the frontend.
 *
 * WHY a separate file?
 * The editor shows a compact placeholder (see edit.js), not the full
 * roadmap. These styles exclusively support that placeholder card.
 * Mixing them into style.scss would create dead CSS on the frontend.
 *
 * @package GatherPressRelations
 */

.wp-block-gatherpress-relations-roadmap {
	/**
	 * Placeholder card wrapper.
	 *
	 * WHY a border + gradient background?
	 * The gradient communicates "this is a special informational block"
	 * and visually differentiates it from plain paragraph blocks in the
	 * editor canvas.
	 */
	.gatherpress-relations__editor-placeholder {
		background: linear-gradient(135deg, #eff6ff 0%, #f5f3ff 100%);
		border: 1px solid #e2e8f0;
		border-radius: 12px;
		padding: 1.75rem;
		min-height: 140px;
	}

	/**
	 * Header row — icon + title side by side.
	 */
	.gatherpress-relations__editor-placeholder-header {
		display: flex;
		align-items: center;
		gap: 0.6rem;
		margin-bottom: 0.75rem;

		/**
		 * Override the default Dashicon colour to match the primary blue.
		 */
		.dashicon,
		svg {
			fill: #3b82f6;
			color: #3b82f6;
		}
	}

	/**
	 * Placeholder title — visually prominent but smaller than an <h2>.
	 */
	.gatherpress-relations__editor-placeholder-title {
		margin: 0;
		font-size: 1.15rem;
		font-weight: 700;
		color: #1e293b;
	}

	/**
	 * Short description of what the block does on the frontend.
	 */
	.gatherpress-relations__editor-placeholder-description {
		font-size: 0.88rem;
		color: #64748b;
		line-height: 1.55;
		margin: 0 0 1rem;
	}

	/**
	 * Section checklist — a visual list of toggleable sections.
	 */
	.gatherpress-relations__editor-placeholder-sections {
		list-style: none;
		margin: 0;
		padding: 0;
		display: grid;
		grid-template-columns: 1fr 1fr;
		gap: 0.35rem 1rem;

		@media (max-width: 600px) {
			grid-template-columns: 1fr;
		}
	}

	/**
	 * Individual section item in the checklist.
	 * Uses a flex layout for icon + label alignment.
	 */
	.gatherpress-relations__editor-placeholder-section {
		display: flex;
		align-items: center;
		gap: 0.4rem;
		font-size: 0.82rem;
		padding: 0.3rem 0.5rem;
		border-radius: 6px;
		transition: opacity 0.15s ease;

		.dashicon,
		svg {
			width: 16px;
			height: 16px;
		}

		/**
		 * Enabled modifier — full opacity + primary icon colour.
		 */
		&--enabled {
			color: #1e293b;

			.dashicon,
			svg {
				fill: #3b82f6;
				color: #3b82f6;
			}
		}

		/**
		 * Disabled modifier — reduced opacity signals the section
		 * is toggled off and won't render on the frontend.
		 */
		&--disabled {
			opacity: 0.4;
			color: #94a3b8;

			.dashicon,
			svg {
				fill: #94a3b8;
				color: #94a3b8;
			}
		}
	}

	/**
	 * Status bar — "X of 6 sections enabled".
	 * Positioned at the bottom of the placeholder card as a subtle
	 * summary line.
	 */
	.gatherpress-relations__editor-placeholder-status {
		margin-top: 1rem;
		padding-top: 0.75rem;
		border-top: 1px solid #e2e8f0;
		font-size: 0.78rem;
		font-weight: 600;
		color: #64748b;
		text-align: right;
	}
}

/**
 * Frontend interactivity for the GatherPress Relations Roadmap block.
 *
 * WHAT this script does:
 * ──────────────────────
 * 1. **Collapsible sections** — Each section header is a <button> that
 *    toggles the `--collapsed` modifier on its parent. The CSS transition
 *    on `max-height` and `opacity` produces a smooth expand/collapse.
 *
 * 2. **Smooth-scroll TOC links** — Clicking a TOC link scrolls the
 *    target section into view with `scrollIntoView({ behavior: 'smooth' })`.
 *
 * 3. **Active TOC highlighting** — An IntersectionObserver watches each
 *    section. When a section enters the viewport, its corresponding TOC
 *    link receives the `--active` modifier class.
 *
 * WHY plain JavaScript?
 * WordPress coding standards for blocks recommend plain JS with standard
 * DOM APIs for frontend interactivity. This avoids framework dependencies,
 * keeps the bundle tiny, and ensures compatibility with any theme.
 *
 * HOW multiple block instances are handled:
 * `querySelectorAll` finds all block instances on the page. Each instance
 * is initialised independently inside a `forEach` loop, so multiple
 * roadmap blocks on the same page do not interfere with each other.
 *
 * @package GatherPressRelations
 */

document.addEventListener( 'DOMContentLoaded', () => {
	/**
	 * Find every instance of the roadmap block on the page.
	 *
	 * WHY querySelectorAll?
	 * A page may contain multiple roadmap blocks (unlikely but possible).
	 * querySelectorAll returns a NodeList of all matches, and we
	 * initialise each one independently.
	 *
	 * @type {NodeListOf<HTMLElement>}
	 */
	const blocks = document.querySelectorAll(
		'.wp-block-gatherpress-relations-roadmap'
	);

	blocks.forEach( ( block ) => {
		initCollapsibleSections( block );
		initTocNavigation( block );
		initTocHighlighting( block );
	} );
} );

/**
 * Initialises collapsible section toggling for a single block instance.
 *
 * HOW it works:
 * ─────────────
 * Each section header is a <button> with `aria-expanded` and
 * `aria-controls` attributes (set by render.php). Clicking the button:
 * 1. Toggles the `--collapsed` CSS modifier on the section wrapper.
 * 2. Flips the `aria-expanded` attribute for screen readers.
 *
 * WHY aria-expanded?
 * It communicates the expand/collapse state to assistive technology.
 * Screen readers announce "collapsed" or "expanded" when the user
 * focuses the button.
 *
 * @param {HTMLElement} block - The block root element.
 * @returns {void}
 */
function initCollapsibleSections( block ) {
	const headers = block.querySelectorAll(
		'.gatherpress-relations__section-header'
	);

	headers.forEach( ( header ) => {
		header.addEventListener( 'click', () => {
			/**
			 * The section wrapper is the parent of the <button>.
			 *
			 * DOM structure (from render.php):
			 * ```html
			 * <div class="gatherpress-relations__section" id="ttr-section-1">
			 *   <button class="gatherpress-relations__section-header" aria-expanded="true" aria-controls="ttr-body-1">
			 *     ...
			 *   </button>
			 *   <div class="gatherpress-relations__section-body" id="ttr-body-1">
			 *     ...
			 *   </div>
			 * </div>
			 * ```
			 */
			const section = header.closest(
				'.gatherpress-relations__section'
			);

			if ( ! section ) {
				return;
			}

			const isCollapsed = section.classList.toggle(
				'gatherpress-relations__section--collapsed'
			);

			/**
			 * Update ARIA state.
			 *
			 * WHY string 'true'/'false'?
			 * `aria-expanded` is a string attribute, not a boolean
			 * DOM property. Setting it to the boolean `true` would
			 * work in most browsers but the spec defines it as an
			 * enumerated string.
			 */
			header.setAttribute(
				'aria-expanded',
				isCollapsed ? 'false' : 'true'
			);
		} );
	} );
}

/**
 * Initialises smooth-scroll behaviour for TOC links.
 *
 * HOW it works:
 * ─────────────
 * Each TOC link has an `href` like `#ttr-section-1`. Clicking it:
 * 1. Prevents the default hash-jump.
 * 2. Finds the target element by ID.
 * 3. Scrolls it into view with `behavior: 'smooth'`.
 * 4. Updates the URL hash without a jump (via `history.pushState`).
 *
 * WHY pushState instead of default hash navigation?
 * Default hash navigation causes an instant jump to the target.
 * `pushState` + `scrollIntoView` gives us smooth scrolling while
 * still updating the URL for shareability and back-button support.
 *
 * @param {HTMLElement} block - The block root element.
 * @returns {void}
 */
function initTocNavigation( block ) {
	const tocLinks = block.querySelectorAll(
		'.gatherpress-relations__toc-link'
	);

	tocLinks.forEach( ( link ) => {
		link.addEventListener( 'click', ( event ) => {
			event.preventDefault();

			const targetId = link.getAttribute( 'href' );

			if ( ! targetId ) {
				return;
			}

			/**
			 * Find the target section within the document (not scoped
			 * to the block) because IDs are document-global.
			 *
			 * @type {HTMLElement|null}
			 */
			const target = document.querySelector( targetId );

			if ( ! target ) {
				return;
			}

			/**
			 * Scroll with an offset to account for the admin bar
			 * and any sticky headers.
			 *
			 * WHY 'smooth'?
			 * Smooth scrolling is a better UX than an instant jump
			 * for intra-page navigation. The browser handles the
			 * easing natively.
			 */
			target.scrollIntoView( {
				behavior: 'smooth',
				block: 'start',
			} );

			/**
			 * Update the URL hash so the section is linkable.
			 */
			if ( window.history && window.history.pushState ) {
				window.history.pushState( null, '', targetId );
			}

			/**
			 * If the section is collapsed, expand it so the user
			 * sees the content they navigated to.
			 */
			if (
				target.classList.contains(
					'gatherpress-relations__section--collapsed'
				)
			) {
				target.classList.remove(
					'gatherpress-relations__section--collapsed'
				);
				const headerBtn = target.querySelector(
					'.gatherpress-relations__section-header'
				);
				if ( headerBtn ) {
					headerBtn.setAttribute( 'aria-expanded', 'true' );
				}
			}
		} );
	} );
}

/**
 * Highlights the active TOC link based on scroll position.
 *
 * HOW it works:
 * ─────────────
 * An IntersectionObserver watches each section element. When a section's
 * top edge crosses the 20% line from the top of the viewport (the
 * `rootMargin`), the observer fires and we mark its TOC link as active.
 *
 * WHY IntersectionObserver instead of scroll events?
 * 1. Performance — IO is optimised by the browser and does not fire
 *    on every scroll pixel.
 * 2. Accuracy — threshold-based detection is more reliable than manual
 *    offset calculations, especially with sticky headers or admin bars.
 * 3. Battery — fewer CPU wake-ups on mobile devices.
 *
 * PAYLOAD (IntersectionObserverEntry):
 * ```
 * {
 *   target:          HTMLElement,    // the observed section
 *   isIntersecting:  boolean,       // whether it crosses the root margin
 *   intersectionRatio: number,      // 0–1, how much is visible
 *   boundingClientRect: DOMRect,
 *   rootBounds:      DOMRect | null
 * }
 * ```
 *
 * @param {HTMLElement} block - The block root element.
 * @returns {void}
 */
function initTocHighlighting( block ) {
	const sections = block.querySelectorAll(
		'.gatherpress-relations__section'
	);
	const tocLinks = block.querySelectorAll(
		'.gatherpress-relations__toc-link'
	);

	if ( sections.length === 0 || tocLinks.length === 0 ) {
		return;
	}

	/**
	 * Observer options.
	 *
	 * WHY rootMargin: '-20% 0px -70% 0px'?
	 * This creates an observation zone that spans from 20% below the
	 * top of the viewport to 30% above the bottom. When a section's
	 * top edge enters this band, it's considered "in view". This
	 * compensates for the admin bar and ensures the active link
	 * updates before the section fills the screen.
	 *
	 * @type {IntersectionObserverInit}
	 */
	const observerOptions = {
		root: null,
		rootMargin: '-20% 0px -70% 0px',
		threshold: 0,
	};

	const observer = new IntersectionObserver( ( entries ) => {
		entries.forEach( ( entry ) => {
			if ( ! entry.isIntersecting ) {
				return;
			}

			const sectionId = entry.target.getAttribute( 'id' );

			if ( ! sectionId ) {
				return;
			}

			/**
			 * Remove the active class from all TOC links in this
			 * block instance, then add it to the matching link.
			 *
			 * WHY scoped to the block?
			 * Multiple block instances should not interfere with
			 * each other's TOC highlighting.
			 */
			tocLinks.forEach( ( link ) => {
				link.classList.remove(
					'gatherpress-relations__toc-link--active'
				);
			} );

			const activeLink = block.querySelector(
				`.gatherpress-relations__toc-link[href="#${ sectionId }"]`
			);

			if ( activeLink ) {
				activeLink.classList.add(
					'gatherpress-relations__toc-link--active'
				);
			}
		} );
	}, observerOptions );

	/**
	 * Observe each section element.
	 */
	sections.forEach( ( section ) => {
		observer.observe( section );
	} );
}

